3182   // for example, by an arithmetic operation, then andIRFlags()
3183   // would just erase all math flags from the original arithmetic
3184   // operation, which is clearly not wanted and not needed.
3185   else if (!isa<LoadInst>(I))
3186     ReplInst->andIRFlags(I);
