1417 MDNode *MDNode::getMostGenericNoaliasAddrspace(MDNode *A, MDNode *B) {
1418   if (!A || !B)
1419     return nullptr;
1420 
1421   if (A == B)
1422     return A;
1423 
1424   SmallVector<ConstantRange> RangeListA, RangeListB;
1425   for (unsigned I = 0, E = A->getNumOperands() / 2; I != E; ++I) {
1426     auto *LowA = mdconst::extract<ConstantInt>(A->getOperand(2 * I + 0));
1427     auto *HighA = mdconst::extract<ConstantInt>(A->getOperand(2 * I + 1));
1428     RangeListA.push_back(ConstantRange(LowA->getValue(), HighA->getValue()));
1429   }
1430 
1431   for (unsigned I = 0, E = B->getNumOperands() / 2; I != E; ++I) {
1432     auto *LowB = mdconst::extract<ConstantInt>(B->getOperand(2 * I + 0));
1433     auto *HighB = mdconst::extract<ConstantInt>(B->getOperand(2 * I + 1));
1434     RangeListB.push_back(ConstantRange(LowB->getValue(), HighB->getValue()));
1435   }
1436 
1437   ConstantRangeList CRLA(RangeListA);
1438   ConstantRangeList CRLB(RangeListB);
1439   ConstantRangeList Result = CRLA.intersectWith(CRLB);
1440   if (Result.empty())
1441     return nullptr;
1442 
1443   SmallVector<Metadata *> MDs;
1444   for (const ConstantRange &CR : Result) {
1445     MDs.push_back(ConstantAsMetadata::get(
1446         ConstantInt::get(A->getContext(), CR.getLower())));
1447     MDs.push_back(ConstantAsMetadata::get(
1448         ConstantInt::get(A->getContext(), CR.getUpper())));
1449   }
1450 
1451   return MDNode::get(A->getContext(), MDs);
1452 }
