2440           .addAttribute(Attribute::Dereferenceable)
2441           .addAttribute(Attribute::DereferenceableOrNull)
2442           .addAttribute(Attribute::Writable)
2443           .addAttribute(Attribute::DeadOnUnwind)
2444           .addAttribute(Attribute::Initializes)
2445           .addAttribute(Attribute::Captures)
