2451           .addAttribute(Attribute::InAlloca)
2452           .addAttribute(Attribute::ByVal)
2453           .addAttribute(Attribute::StructRet)
2454           .addAttribute(Attribute::ByRef)
2455           .addAttribute(Attribute::ElementType)
